<script>
    $(window).on('load',  function(){
        getListKategori();
        if (feather) feather.replace({ width: 14, height: 14 });

        $('.select2').select2({
            placeholder: '- Pilih Kategori -',
            ajax: {
                url: '{{ url('api/get-kategori-faq/select2') }}',
                dataType: 'json',
                success: (data) => {
                    console.log(data);
                },
                processResults: function (data) {
                    return {
                        results: data.data
                    };
                }
            }
        });

        $('.select2').on('select2:select', function (e) {
            const data = e.params.data;
            $('html, body').animate({
                scrollTop: $(`#${data.text}`).offset().top
            }, 1400);
        });

        $(document).on('click', '.click-kategori', function () {
           const id = $(this).data('id');
           console.log(id);
            $('html, body').animate({
                scrollTop: $(`#${id}`).offset().top
            }, 1400);
        });

        function getListKategori() {
            $.ajax({
                type: "get",
                url: '{{ url('api/get-kategori-faq/select2')}}',
                dataType: "json",
                success: function (response) {
                    response.data.reverse();
                    response.data.forEach((item, index) => {
                        $('#listKategori').append(`<p class="mt-1 click-kategori" style="cursor: pointer" data-id="${item.text}">${item.text}</p>`)
                    })
                    feather.replace()
                }
            });
        }
    })
</script>
